SELECT X.*
FROM ( SELECT TVUR.USER_ID AS USER_ID , TVUR.USER_NM AS USER_NM
, TVUR.ENTRY_GB , TVUR.RELATION_ID , TVUR.DIPSA_DAY , TVUR.CONFIRM_DATE , TVUR.CONFIRM_USER_ID , TVUR.CR_DATETIME , TVUR.CR_SABUN_NAME
, TVUR.EMPLOYEE_NO , TVUR.GEUNMU_STS
, TVUR.SUBCUST_NAME , TVUR.CUST_NAME , TVUR.START_CONTRACT , TVUR.END_CONTRACT , TVUR.EMAIL AS EMAIL , REGEXP_REPLACE(REGEXP_REPLACE(TVUR.CELL_NUM ,'[^0-9]',''),'(.{3})(.+)(.{4})','\1-\2-\3') AS CELL_NUM , TVUR.PROGRESS_CD , TVUR.SITE_USER_ID , getUserName(TVUR.GATE_CD, TVUR.SITE_USER_ID, #{ses.langCd}) AS SITE_USER_NM , TVUR.GENDER , TVUR.BIRTH_DATE AS BIRTH_DATE , TVUR.CONFIRM_USER_ID AS SIGN_USER_ID , getUserName(TVUR.GATE_CD, TVUR.CONFIRM_USER_ID, #{ses.langCd}) AS SIGN_USER_NM
, (CASE WHEN TVUR.PROGRESS_CD = 'P' THEN '1' WHEN TVUR.PROGRESS_CD = 'R' THEN '2' ELSE '3' END) AS SORT_ORD , GETCODENAME(TVUR.GATE_CD, 'M044', TVUR.DEL_FLAG, #{ses.langCd}) AS USER_DEL_FLAG , TVUR.SLEEP_ACC FROM STOCTVUR TVUR WHERE TVUR.GATE_CD = #{ses.gateCd} AND TVUR.USER_TYPE = 'T'
AND TVUR.SITE_USER_ID = #{ses.userId}
AND TVUR.CUST_CODE = #{CUST_CODE}
AND TVUR.SUBCUST_CODE = #{SUBCUST_CODE}
AND TVUR.CUST_NAME LIKE '%' #{CUST_NAME}'%'
AND TVUR.SUBCUST_NAME LIKE '%' #{SUBCUST_NAME}'%'
AND TVUR.USER_NM LIKE '%' #{USER_NM}'%'
) X WHERE 1 = 1 ORDER BY X.SORT_ORD , X.USER_NM

mapper.update:
UPDATE STOCTVUR TVUR
   SET RELATION_ID = #{RELATION_ID}
 WHERE TVUR.GATE_CD   = #{ses.gateCd}
   AND TVUR.USER_ID   = #{USER_ID}

UPDATE STOCTVUR TVUR
   SET MOD_DATE    = SYSDATE
     , MOD_USER_ID = #{ses.userId}
     , PROGRESS_CD = #{PROGRESS_CD}

     , CONFIRM_DATE    = SYSDATE
     , CONFIRM_USER_ID = #{ses.userId}

 WHERE TVUR.GATE_CD   = #{ses.gateCd}
   AND TVUR.USER_ID   = #{USER_ID}
   AND TVUR.USER_TYPE = 'T'

