mapper.insert:
INSERT INTO STOCTUPW (
        GATE_CD
      , USER_ID
      , REG_DATE
      , REG_USER_ID
      , PASSWORD
      , REG_IP_ADDR
) VALUES (
        #{ses.gateCd}
      , UPPER((SF_TRIM(#{sabun})))
      , SYSDATE
      , #{ses.userId}
      , #{PASSWORD}
      , #{REG_IP_ADDR}
)
